    ast.alias, ast.withitem,
}

# Whitelist of allowed function names
ALLOWED_FUNCTIONS = {
    'len', 'range', 'str', 'int', 'float', 'list', 'dict', 'tuple', 'set', 'bool',
    'abs', 'sum', 'min', 'max', 'sorted', 'enumerate', 'zip', 'map', 'filter',
}

def is_safe_code(tree):
    """Check if the AST only contains allowed node types (expression-only)."""
    for node in ast.walk(tree):
        if type(node) not in ALLOWED_NODES:
            return False

        # Check that function calls are only to whitelisted functions
        if isinstance(node, ast.Call):
            if isinstance(node.func, ast.Name):
                if node.func.id not in ALLOWED_FUNCTIONS:
                    return False
            elif isinstance(node.func, ast.Attribute):
                # Disallow attribute access on function calls for safety
                return False

    # Ensure it's only expressions, not statements that could be dangerous
    if not isinstance(tree, ast.Expression):
        return False

    return True

class SafeEvaluator(ast.NodeVisitor):
    """Safely evaluate AST nodes without using eval()."""

    def __init__(self, restricted_builtins):
        self.restricted_builtins = restricted_builtins
        self.local_vars = {}

    def visit_Constant(self, node):
        return node.value

    def visit_Num(self, node):
        return node.n

    def visit_Str(self, node):
        return node.s

    def visit_Bytes(self, node):
        return node.s

    def visit_NameConstant(self, node):
        return node.value

    def visit_Ellipsis(self, node):
        return ...

    def visit_List(self, node):
        return [self.visit(elt) for elt in node.elts]

    def visit_Tuple(self, node):
        return tuple(self.visit(elt) for elt in node.elts)

    def visit_Dict(self, node):
        return {self.visit(k): self.visit(v) for k, v in zip(node.keys, node.values)}

    def visit_Set(self, node):
        return {self.visit(elt) for elt in node.elts}

    def visit_Name(self, node):
        if node.id in self.restricted_builtins:
            return self.restricted_builtins[node.id]
        raise NameError(f"Name '{node.id}' is not allowed")

    def visit_BinOp(self, node):
        left = self.visit(node.left)
        right = self.visit(node.right)
        op = node.op

        ops = {
            ast.Add: operator.add,
            ast.Sub: operator.sub,
            ast.Mult: operator.mul,
            ast.Div: operator.truediv,
            ast.FloorDiv: operator.floordiv,
            ast.Mod: operator.mod,
            ast.Pow: operator.pow,
            ast.LShift: operator.lshift,
            ast.RShift: operator.rshift,
            ast.BitOr: operator.or_,
            ast.BitXor: operator.xor,
            ast.BitAnd: operator.and_,
            ast.MatMult: operator.matmul,
        }

        if type(op) not in ops:
            raise ValueError(f"Unsupported binary operator: {type(op)}")

        return ops[type(op)](left, right)

    def visit_UnaryOp(self, node):
        operand = self.visit(node.operand)
        op = node.op

        ops = {
            ast.Invert: operator.invert,
            ast.Not: operator.not_,
            ast.UAdd: operator.pos,
            ast.USub: operator.neg,
        }

        if type(op) not in ops:
            raise ValueError(f"Unsupported unary operator: {type(op)}")

        return ops[type(op)](operand)

    def visit_Compare(self, node):
        left = self.visit(node.left)

        ops = {
            ast.Eq: operator.eq,
            ast.NotEq: operator.ne,
            ast.Lt: operator.lt,
            ast.LtE: operator.le,
            ast.Gt: operator.gt,
            ast.GtE: operator.ge,
            ast.Is: operator.is_,
            ast.IsNot: operator.is_not,
            ast.In: lambda x, y: x in y,
            ast.NotIn: lambda x, y: x not in y,
        }

        result = True
        for op, comparator in zip(node.ops, node.comparators):
            right = self.visit(comparator)
            if type(op) not in ops:
                raise ValueError(f"Unsupported comparison operator: {type(op)}")
            result = result and ops[type(op)](left, right)
            left = right

        return result

    def visit_Call(self, node):
        if isinstance(node.func, ast.Name):
            func = self.visit(node.func)
            args = [self.visit(arg) for arg in node.args]
            kwargs = {kw.arg: self.visit(kw.value) for kw in node.keywords}
            return func(*args, **kwargs)
        else:
            raise ValueError("Only direct function calls are allowed")

    def visit_IfExp(self, node):
        test = self.visit(node.test)
        if test:
            return self.visit(node.body)
        else:
            return self.visit(node.orelse)

    def visit_Subscript(self, node):
        value = self.visit(node.value)
        slice_val = self.visit(node.slice)
        return value[slice_val]

    def visit_Attribute(self, node):
        raise ValueError("Attribute access is not allowed")

    def visit_Lambda(self, node):
        raise ValueError("Lambda functions are not allowed")

    def visit_ListComp(self, node):
        raise ValueError("List comprehensions are not allowed")

    def visit_SetComp(self, node):
        raise ValueError("Set comprehensions are not allowed")

    def visit_DictComp(self, node):
        raise ValueError("Dict comprehensions are not allowed")

    def visit_GeneratorExp(self, node):
        raise ValueError("Generator expressions are not allowed")

    def generic_visit(self, node):
        raise ValueError(f"Unsupported node type: {type(node).__name__}")

def safe_eval(code, restricted_builtins):
    """Safely evaluate code using AST visitor without eval()."""
    try:
        # First try literal_eval for safe literal values
        return ast.literal_eval(code)
    except (ValueError, SyntaxError):
        # If not a literal, parse and validate the AST
        try:
            tree = ast.parse(code, mode='eval')
        except SyntaxError as e:
            raise SyntaxError(f'Syntax error: {str(e)}')

        # Validate that code only contains safe expressions
        if not is_safe_code(tree):
            raise ValueError('Code contains disallowed operations')

        # Use AST visitor to safely evaluate without eval()
        evaluator = SafeEvaluator(restricted_builtins)
        return evaluator.visit(tree.body)

@app.route("/evalcode")
def eval_code():
    '''
    Get the user input from the request, 
    evaluate it as a safe expression only.
    '''
    try:
        code = request.args.get('code', '')

        if not code:
            return {'error': 'No code provided'}, 400

        # Create a restricted environment with limited builtins
        restricted_builtins = {
            'len': len,
            'range': range,
            'str': str,
            'int': int,
            'float': float,
            'list': list,
            'dict': dict,
            'tuple': tuple,
            'set': set,
            'bool': bool,
            'abs': abs,
            'sum': sum,
            'min': min,
            'max': max,
            'sorted': sorted,
            'enumerate': enumerate,
            'zip': zip,
            'map': map,
            'filter': filter,
        }

        # Capture output
        output_buffer = StringIO()
        old_stdout = sys.stdout
        sys.stdout = output_buffer

        try:
            # Safely evaluate the code
            result = safe_eval(code, restricted_builtins)

            output = output_buffer.getvalue()
            if result is not None:
                output += str(result)

            return {'output': output}, 200
        except (SyntaxError, ValueError, NameError, TypeError) as e:
            return {'error': str(e)}, 400
        finally:
            sys.stdout = old_stdout

    except Exception as e:
        return {'error': f'Execution error: {str(e)}'}, 500

from flask import Flask, request

app = Flask(__name__)

@app.route('/')
def index():
    '''
    Get the module version from the request object
    importing the urllib module with the version by using exec()
    '''
    module_name = request.args.get('module', 'urllib')

    # Validate module name to prevent code injection
    if not module_name.isidentifier():
        return "Invalid module name", 400

    # Whitelist of allowed modules
    allowed_modules = {'urllib', 'urllib.request', 'urllib.parse', 'urllib.error'}
    if module_name not in allowed_modules:
        return "Module not allowed", 403

    try:
        namespace = {}
        exec(f"import {module_name}", namespace)
        module = namespace[module_name.split('.')[0]]

        # Navigate to the correct submodule if needed
        for part in module_name.split('.')[1:]:
            module = getattr(module, part)

        version = getattr(module, '__version__', 'Version not available')
        return f"Module: {module_name}, Version: {version}"
    except Exception as e:
        return f"Error: {str(e)}", 500

