from flask import Flask, request, jsonify
import yaml

app = Flask(__name__)

@app.route('/yaml', methods=['POST', 'GET'])
def yaml_load():
    '''
    Get YAML data from request, parse it, and return it.
    '''
    try:
        # Get YAML data from request
        if request.method == 'POST':
            data = request.get_data(as_text=True)
        else:
            data = request.args.get('data', '')

        if not data:
            return jsonify({'error': 'No YAML data provided'}), 400

        # Parse YAML safely using safe_load to prevent arbitrary code execution
        parsed_data = yaml.safe_load(data)

        # Return parsed data as JSON
        return jsonify(parsed_data)

    except yaml.YAMLError as e:
        return jsonify({'error': f'Invalid YAML: {str(e)}'}), 400
    except Exception as e:
        return jsonify({'error': f'An error occurred: {str(e)}'}), 500
